// packages/api-contracts/src/clinical-workspace/protected-route.js
function deriveProtectedRouteDecision(identity, route) {
  const roleScope = roleScopeForStaffIdentity(identity);
  if (identity.state !== "known") {
    return decision(identity, false, "blocked", "Staff identity must be confirmed before workspace controls appear.", roleScope);
  }
  if (route.key === "workspaceApprovals" && roleScope !== "supervisor") {
    return decision(identity, true, "read_only", "Approval list is visible, but approval controls require supervisor access.", roleScope);
  }
  if (route.key === "workspaceCreateIntake" || route.key === "workspaceIntakeInspector") {
    if (roleScope === "observer") {
      return decision(identity, false, "blocked", "Intake workspace requires clinician access.", roleScope);
    }
    return decision(identity, true, "writable", "Intake workspace is ready.", roleScope);
  }
  if (roleScope === "observer") {
    return decision(identity, true, "read_only", "Observer access can review details, but actions stay unavailable.", roleScope);
  }
  if (route.key === "workspaceChanged") {
    return decision(identity, true, "recovery_only", "Updated requests stay open for recheck until the selected task is ready.", roleScope);
  }
  return decision(identity, true, "writable", "Workspace access is current.", roleScope);
}
function roleScopeForStaffIdentity(identity) {
  const roleScopeRefs = identity.roleScopeRefs.map(normalizedStaffRoleRef);
  if (roleScopeRefs.some((role) => role === "clinical_supervisor" || role === "supervisor")) {
    return "supervisor";
  }
  if (roleScopeRefs.some((role) => role === "clinical_reviewer" || role === "reviewer" || role === "clinician")) {
    return "clinician";
  }
  return "observer";
}
function decision(identity, allowed, writability, reason, roleScope) {
  return {
    allowed,
    writability,
    reason,
    actingContext: {
      actingContextRef: `acting-${roleScope}:${safeStaffRef(identity.staffRef)}`,
      roleScope,
      queueScopeRefs: ["urgent", "routine", "returns"],
      routeWritability: writability,
      reason
    }
  };
}
function safeStaffRef(staffRef) {
  const normalized = staffRef.trim().replace(/[^A-Za-z0-9._:-]+/gu, "-").replace(/^-+|-+$/gu, "");
  return normalized.length > 0 ? normalized.slice(0, 120) : "unknown";
}
function normalizedStaffRoleRef(roleScopeRef) {
  const parts = roleScopeRef.trim().toLowerCase().split(":").filter((part) => part.length > 0);
  const localRoleRef = parts.length > 0 ? parts[parts.length - 1] ?? "" : roleScopeRef;
  return localRoleRef.replace(/[^a-z0-9]+/gu, "_").replace(/^_+|_+$/gu, "");
}

